    """Check every available shelf for the model. Download into the primary on miss."""
    checks: list[dict] = []

    for parent in list_shelf_candidates(config):
        candidate = shelf_path_gguf(parent, repo_id, quant)
        shelf = parent / "gguf"
        if candidate.is_file():
