            rel = f.relative_to(root)
        except ValueError:
            continue
        if ".cache" in rel.parts:
            continue
        try:
            st = f.stat()
        except OSError:
            continue
        entries.append((f, st.st_size, "hf-cache"))
    return entries


def _build_sha256_index(
