        except OSError:
            skipped_cross_fs += 1
            continue
        _hardlink_replace(canonical, other)
        hardlinks_created += 1
    return hardlinks_created, skipped_cross_fs


# ---------------------------------------------------------------------------
# Public API — scan
# ---------------------------------------------------------------------------


def find_duplicates(
